"use client";
import { useState, useEffect, useRef } from "react";

// ============ ENHANCEMENT UTILITIES ============

// #2 Haptic feedback
const haptic = (type = "light") => {
  if (!navigator.vibrate) return;
  const patterns = { light: [10], medium: [20], success: [10, 50, 10, 50, 20] };
  try { navigator.vibrate(patterns[type] || [10]); } catch(e) {}
};

// #5 Animated counter for hero stats
function AnimatedStat({ text, delay = 0 }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  const [count, setCount] = useState(0);
  const numMatch = text.match(/^([\d.]+)/);
  const num = numMatch ? parseFloat(numMatch[1]) : null;
  const suffix = numMatch ? text.replace(numMatch[1], "") : text;

  useEffect(() => {
    const el = ref.current; if (!el) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setTimeout(() => setVis(true), delay); obs.disconnect(); } }, { threshold: 0.3 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [delay]);

  useEffect(() => {
    if (!vis || num === null) return;
    let start = null; const dur = 1200;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / dur, 1);
      const ease = 1 - Math.pow(1 - p, 3);
      setCount(num % 1 !== 0 ? parseFloat((num * ease).toFixed(1)) : Math.round(num * ease));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [vis, num]);

  return <span ref={ref}>{vis && num !== null ? `${count}${suffix}` : text}</span>;
}

// #8 Scroll-triggered reveal
function Reveal({ children, delay = 0, direction = "up" }) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setTimeout(() => setVis(true), delay); obs.disconnect(); } }, { threshold: 0.1 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [delay]);
  const transforms = { up: "translateY(24px)", left: "translateX(-24px)", right: "translateX(24px)" };
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? "translate(0)" : (transforms[direction] || transforms.up),
      transition: `opacity 0.6s ease, transform 0.6s ease`,
    }}>{children}</div>
  );
}

// #9 Button press style
